    public static readonly classSampleDiv_Red = "sampleDiv_Red";
    public static readonly classSampleDiv_Bleu = "sampleDiv_Bleu";
    public static readonly classSampleDiv_Green = "sampleDiv_Green";

    public static readonly classSampleLabel = "sampleLabel";

    // --------------------------- //
    //     Generation de contenu   //
    // --------------------------- //
    /** Permet de créer une div sample, pour avoir une couleur random mettre -1 */
    public static divSample(nbColor?: number)
    {
        let classSampleDiv = "";
        if (nbColor == -1)
            nbColor = Math.floor(Math.random() * 3)+1;
        if (!nbColor)
            nbColor = 1;

        switch (nbColor)
        {
            case 2:
                classSampleDiv = xxShowRoomSample.classSampleDiv_Bleu;
                break;
            case 3:
                classSampleDiv = xxShowRoomSample.classSampleDiv_Green;
                break;
            default:
                classSampleDiv = xxShowRoomSample.classSampleDiv_Red;
        }

        return new xDiv({ class: classSampleDiv});
    }

