class xxShowroomCustomSample
{
    public nom: string;
    public Group: string;
    public couleur: string

    constructor(nom: string, Group: string, couleur: string)
    {
        this.nom = nom;
        this.Group = Group;
        this.couleur = couleur
    }

    public toString()
    {
        return this.nom + " est un " + this.Group;
    }
}